def count_visible_nodes(root):
    def dfs(node, max_height):
        if not node:
            return 0
        count = 0
        if node.val >= max_height:
            count = 1
            max_height = node.val
        return count + dfs(node.left, max_height) + dfs(node.right, max_height)

    return dfs(root, float('-inf'))

